mapper.insert:
/* reuseUsimMgmtMapper.insertReuseUsimMst */
INSERT INTO MSP_REUSE_USIM_MST(
	REUSE_SEQ
	,CONTRACT_NUM
	,USIM_NO
	,USIM_STATUS
	,REG_RSN
	,REGST_ID
	,REGST_DTTM
)VALUES(
    REUSE_USIM_SEQ.NEXTVAL
	,#{contractNum, jdbcType=VARCHAR}
	,#{iccId, jdbcType=VARCHAR}
	,#{usimStatus, jdbcType=VARCHAR}
	,#{regRsn, jdbcType=VARCHAR}
	,#{sessionUserId}
	, SYSDATE
)

mapper.select:
		/* reuseUsimMgmtMapper.insertReuseUsimtMst */

SELECT  COUNT(1)
FROM    MSP_REUSE_USIM_MST A
WHERE  A.USIM_NO =  #{iccId}

mapper.insert:
		/* reuseUsimMgmtMapper.insertReuseUsimHist */
	INSERT INTO MSP_REUSE_USIM_HIST(
			CONTRACT_NUM
			,USIM_NO
			,USIM_STATUS
			,REG_RSN
            ,RATE_CD
            ,SUB_STATUS
			,REGST_ID
			,REGST_DTTM
		)VALUES(
			#{contractNum, jdbcType=VARCHAR}
			,#{iccId, jdbcType=VARCHAR}
			,#{usimStatus, jdbcType=VARCHAR}
			,#{regRsn, jdbcType=VARCHAR}
            ,#{lstRateCd, jdbcType=VARCHAR}
            ,#{subStatus, jdbcType=VARCHAR}
			,#{sessionUserId}
			, SYSDATE
		)

mapper.select:
/* reuseUsimMgmtMapper.selectReuseUsimList */
SELECT RE.REUSE_SEQ ,RE.CONTRACT_NUM ,RE.USIM_NO ,SUB.SUBSCRIBER_NO ,SUB.SUB_LINK_NAME ,REQ.REQ_BUY_TYPE_NM ,REQ.OPER_TYPE_NM ,REQ.FST_RATE_CD ,REQ.FST_RATE_NM ,REQ.LST_RATE_CD ,REQ.LST_RATE_NM ,SUB.SUB_STATUS ,FN_GET_CODENM('MSP0003' , SUB.SUB_STATUS) AS SUB_STATUS_NM ,CASE WHEN SUB.SUB_STATUS = 'C' THEN CASE WHEN 0 = TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '당일개통취소' WHEN 15 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '14일이내해지' WHEN 90 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS CAN_RSN ,FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE) AS ON_OFF_TYPE_NM ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM ,TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE ,TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'C',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS CAN_DATE ,CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS USIM_ORG_NM ,FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM ,FN_GET_CODENM('RCP2001', R.ONLINE_AUTH_TYPE) AS AUTH_TYPE ,REQ.FST_USIM_NO ,RE.USIM_STATUS ,FN_GET_CODENM('VOC0022' , RE.USIM_STATUS) AS USIM_STATUS_NM ,RE.REG_RSN ,FN_GET_CODENM('VOC0021' , RE.REG_RSN) AS REG_RSN_NM ,TO_CHAR(RE.REGST_DTTM , 'YYYY-MM-DD' ) AS REG_DTTM FROM MSP_REUSE_USIM_MST RE ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL REQ ,MSP_PARTNER_USIM_MST PUM ,MSP_REQUEST R ,NMCP_USIM_BUY_TXN@DL_MCP MSD WHERE RE.CONTRACT_NUM = SUB.CONTRACT_NUM AND RE.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND REQ.CONTRACT_NUM = R.CONTRACT_NUM(+) AND REQ.RES_NO = R.RES_NO(+)
AND RE.REGST_DTTM BETWEEN TO_DATE(#{strtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDt} || '235959', 'YYYYMMDDHH24MISS')
AND RE.USIM_STATUS = #{pUsimStatus}
AND RE.CONTRACT_NUM = #{searchName}
AND SUB.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND RE.USIM_NO LIKE '%' || #{searchName} || '%'
ORDER BY RE.REGST_DTTM DESC

mapper.update:
/* reuseUsimMgmtMapper.updateReuseUsimMst */

UPDATE MSP_REUSE_USIM_MST
	SET USIM_STATUS = #{usimStatus}
	      ,REG_RSN = #{regRsn}
	      ,RVISN_ID = #{sessionUserId}
		 ,RVISN_DTTM = SYSDATE
	WHERE REUSE_SEQ = #{reuseSeq}

mapper.select:
/* reuseUsimMgmtMapper.selectReuseUsimListExcel */ SELECT RE.CONTRACT_NUM ,RE.USIM_NO ,SUB.SUBSCRIBER_NO ,SUB.SUB_LINK_NAME ,REQ.REQ_BUY_TYPE_NM ,REQ.OPER_TYPE_NM ,REQ.FST_RATE_CD ,REQ.FST_RATE_NM ,REQ.LST_RATE_CD ,REQ.LST_RATE_NM ,SUB.SUB_STATUS ,FN_GET_CODENM('MSP0003' , SUB.SUB_STATUS) AS SUB_STATUS_NM ,CASE WHEN SUB.SUB_STATUS = 'C' THEN CASE WHEN 0 = TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '당일개통취소' WHEN 15 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '14일이내해지' WHEN 90 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS CAN_RSN ,FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE) AS ON_OFF_TYPE_NM ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM ,TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE ,TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'C',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS CAN_DATE ,CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS USIM_ORG_NM ,FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM ,FN_GET_CODENM('RCP2001', R.ONLINE_AUTH_TYPE) AS AUTH_TYPE ,REQ.FST_USIM_NO ,RE.USIM_STATUS ,FN_GET_CODENM('VOC0022' , RE.USIM_STATUS) AS USIM_STATUS_NM ,RE.REG_RSN ,FN_GET_CODENM('VOC0021' , RE.REG_RSN) AS REG_RSN_NM ,TO_CHAR(RE.REGST_DTTM , 'YYYY-MM-DD' ) AS REG_DTTM FROM MSP_REUSE_USIM_MST RE ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL REQ ,MSP_PARTNER_USIM_MST PUM ,MSP_REQUEST R ,NMCP_USIM_BUY_TXN@DL_MCP MSD WHERE RE.CONTRACT_NUM = SUB.CONTRACT_NUM AND RE.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND REQ.CONTRACT_NUM = R.CONTRACT_NUM(+) AND REQ.RES_NO = R.RES_NO(+)
AND RE.REGST_DTTM BETWEEN TO_DATE(#{strtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDt} || '235959', 'YYYYMMDDHH24MISS')
AND RE.USIM_STATUS = #{pUsimStatus}
AND RE.CONTRACT_NUM = #{searchName}
AND SUB.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND RE.USIM_NO LIKE '%' || #{searchName} || '%'
ORDER BY RE.REGST_DTTM DESC

/* reuseUsimMgmtMapper.getRealUsim */
SELECT USIM_NO
  FROM MSP_REUSE_USIM_MST
 WHERE REUSE_SEQ = #{reuseSeq}

/* reuseUsimMgmtMapper.getContUsim */
SELECT ICC_ID
  FROM MSP_JUO_SUB_INFO
 WHERE CONTRACT_NUM = #{contractNum}
